package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class JsonElementTest {

  // Concrete subclass for testing isJsonObject
  static class JsonObjectSubclass extends JsonObject {
    @Override
    public JsonElement deepCopy() {
      return new JsonObjectSubclass();
    }
  }

  static class JsonArraySubclass extends JsonArray {
    @Override
    public JsonElement deepCopy() {
      return new JsonArraySubclass();
    }
  }

  static class JsonPrimitiveSubclass extends JsonPrimitive {
    JsonPrimitiveSubclass(String value) {
      super(value);
    }
    @Override
    public JsonElement deepCopy() {
      return new JsonPrimitiveSubclass(getAsString());
    }
  }

  static class JsonNullSubclass extends JsonNull {
    @Override
    public JsonElement deepCopy() {
      return this;
    }
  }

  @Test
  void testIsJsonObject_whenInstanceIsJsonObject_shouldReturnTrue() {
    JsonElement jsonObject = new JsonObjectSubclass();
    assertTrue(jsonObject.isJsonObject());
  }

  @Test
  void testIsJsonObject_whenInstanceIsJsonArray_shouldReturnFalse() {
    JsonElement jsonArray = new JsonArraySubclass();
    assertFalse(jsonArray.isJsonObject());
  }

  @Test
  void testIsJsonObject_whenInstanceIsJsonPrimitive_shouldReturnFalse() {
    JsonElement jsonPrimitive = new JsonPrimitiveSubclass("value");
    assertFalse(jsonPrimitive.isJsonObject());
  }

  @Test
  void testIsJsonObject_whenInstanceIsJsonNull_shouldReturnFalse() {
    JsonElement jsonNull = new JsonNullSubclass();
    assertFalse(jsonNull.isJsonObject());
  }
}
